import java.util.List;

public class TypeSafetyDemo {
    // PECS: Producer Extends
    public static double sumList(List<? extends Number> list) {
        return list.stream().mapToDouble(Number::doubleValue).sum();
    }

    public static void main(String[] args) {
        var integers = List.of(1, 2, 3);       // var infers List<Integer>
        var doubles  = List.of(1.5, 2.5, 3.0); // var infers List<Double>

        System.out.println(sumList(integers)); // 6.0
        System.out.println(sumList(doubles));  // 7.0
    }
}

import java.lang.ref.WeakReference;

public class MemoryDemo {
    private static final Map<String, WeakReference<ExpensiveObject>> cache = new HashMap<>();

    public static ExpensiveObject get(String key) {
        WeakReference<ExpensiveObject> ref = cache.get(key);
        ExpensiveObject obj = (ref != null) ? ref.get() : null;
        if (obj == null) {
            obj = new ExpensiveObject(key);
            cache.put(key, new WeakReference<>(obj));
        }
        return obj;
    }
}

import java.util.concurrent.*;

void fetchAll(List<String> urls) throws Exception {
    try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
        List<StructuredTaskScope.Subtask<String>> tasks = urls.stream()
            .map(url -> scope.fork(() -> httpClient.get(url)))
            .toList();

        scope.join().throwIfFailed();

        tasks.stream()
            .map(StructuredTaskScope.Subtask::get)
            .forEach(System.out::println);
    }
}

// Sealed Result type (Java 17+)
sealed interface Result<T> permits Result.Ok, Result.Err {
    record Ok<T>(T value) implements Result<T> {}
    record Err<T>(String message) implements Result<T> {}
}

