// 100k concurrent tasks — no thread pool tuning, no reactive boilerplate

import java.util.concurrent.Executors;
import java.net.http.*;
import java.net.URI;

public class VirtualThreadScaling {
    public static void main(String[] args) throws Exception {
        var client = HttpClient.newHttpClient();
        // Platform threads: ~200 concurrent before thread exhaustion
        // Virtual threads: 100,000+ with same memory budget
        try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < 10_000; i++) {
                executor.submit(() -> {
                    var req = HttpRequest.newBuilder(URI.create("https://api.example.com/data")).build();
                    client.send(req, HttpResponse.BodyHandlers.ofString()); // blocking I/O is fine here
                });
            }
        }
    }
}
